import Foundation

enum AccessibilityAnalyzerMock {
    struct Mock {
        let component: String
        let response: PromptResponse
    }
    
    static func getPurposeMock(for component: String) -> PromptResponse {
        let mocks = [
            transactionReviewCardPurposeMock,
            savingsGoalProgressCardPurposeMock,
            securitySettingsScreenPurposeMock,
            recipientPickerRowPurposeMock
        ]
        let firstMatch = mocks.first(where: { $0.component == component }) ?? mocks[0]
        return firstMatch.response
    }
    
    static func getFormalChecksMock(for component: String) -> PromptResponse {
        let mocks = [
            transactionReviewCardFormalChecksMock,
            savingsGoalProgressCardFormalChecksMock,
            securitySettingsScreenFormalChecksMock,
            recipientPickerRowFormalChecksMock
        ]
        let firstMatch = mocks.first(where: { $0.component == component }) ?? mocks[0]
        return firstMatch.response
    }
    
    static func getHeuristicChecksMock(for component: String) -> PromptResponse {
        let mocks = [
            transactionReviewCardHeuristicChecksMock,
            savingsGoalProgressCardHeuristicChecksMock,
            securitySettingsScreenHeuristicChecksMock,
            recipientPickerRowHeuristicChecksMock
        ]
        let firstMatch = mocks.first(where: { $0.component == component }) ?? mocks[0]
        return firstMatch.response
    }
}

